sysevent_script_action.script:
// Get the currently logged-in user object
var currentUser = gs.getUser();

// Check if the user has the manager role, BUT ensure they are NOT a System Admin
if (currentUser.hasRole('x_1977323_smartlic.manager') && !currentUser.hasRole('admin')) {

    var dashboardPath = '/now/platform-analytics-workspace/dashboards/params/edit/false/sys-id/8b13436193500310b439f04bdd03d62f';

    // Method 1: Standard session redirect
    session.putProperty('login_redirect', dashboardPath);

    // Method 2: Bulletproof for Next Experience UI
    // This permanently locks their unified navigation landing page to your dashboard
    currentUser.savePreference('my_home_navigation_page', dashboardPath);
}
